-- 20260621094136410_baseline.sql
-- Authoritative baseline: the complete managed schema as it exists in production.
-- Generated by introspecting the live database (single source of truth for current state),
-- replacing the prior 96 synthetic/backfilled migrations (archived under _archive/).
--
-- Managed surface: schema `kortix` (tables, enums, indexes, constraints, RLS, functions)
-- plus the billing objects in `public` (atomic_* RPCs + idempotency tables).
--
-- Prerequisites provisioned OUTSIDE this system (must exist before this runs on a fresh DB):
--   - Supabase Auth schema (auth.users, auth.uid(), auth.role())
--   - Basejump accounts (basejump.account_user)
--   - Roles: anon, authenticated, service_role
--
-- Safe to run on an empty (prerequisite-satisfied) database. On existing environments
-- this is marked-applied without running (the schema already exists).

-- ── Scaffolding ──────────────────────────────────────────────────────────────
CREATE SCHEMA IF NOT EXISTS kortix;
CREATE SCHEMA IF NOT EXISTS basejump;

GRANT USAGE ON SCHEMA kortix TO anon, authenticated, service_role;
ALTER DEFAULT PRIVILEGES IN SCHEMA kortix GRANT ALL ON TABLES TO service_role;
ALTER DEFAULT PRIVILEGES IN SCHEMA kortix GRANT SELECT, INSERT, UPDATE ON TABLES TO authenticated;
ALTER DEFAULT PRIVILEGES IN SCHEMA kortix GRANT SELECT ON TABLES TO anon;

-- ── kortix schema (types, tables, constraints, indexes, RLS, functions) ──────
