CREATE TABLE kortix.triggers (
    trigger_id uuid DEFAULT gen_random_uuid() NOT NULL,
    sandbox_id uuid NOT NULL,
    account_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    description text,
    cron_expr character varying(100) NOT NULL,
    timezone character varying(50) DEFAULT 'UTC'::character varying NOT NULL,
    agent_name character varying(255),
    prompt text NOT NULL,
    session_mode kortix.session_mode DEFAULT 'new'::kortix.session_mode NOT NULL,
    session_id text,
    is_active boolean DEFAULT true NOT NULL,
    max_retries integer DEFAULT 0 NOT NULL,
    timeout_ms integer DEFAULT 300000 NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb,
    last_run_at timestamp with time zone,
    next_run_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    model_provider_id character varying(255),
    model_id character varying(255)
);
CREATE TABLE kortix.tunnel_audit_logs (
