CREATE POLICY "Service role can manage all credit balances" ON kortix.credit_balance TO service_role USING ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Service role can manage all credit purchases" ON kortix.credit_purchases TO service_role USING ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Service role can manage all credit usage" ON kortix.credit_usage TO service_role USING ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Service role can manage deletion requests" ON kortix.account_deletion_requests USING ((auth.role() = 'service_role'::text));
CREATE POLICY "Service role manages credit accounts" ON kortix.credit_accounts TO service_role USING ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Service role manages ledger" ON kortix.credit_ledger TO service_role USING ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Users can view own credit account" ON kortix.credit_accounts FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM basejump.account_user au
  WHERE ((au.account_id = credit_accounts.account_id) AND (au.user_id = auth.uid())))));
CREATE POLICY "Users can view own ledger" ON kortix.credit_ledger FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM basejump.account_user au
  WHERE ((au.account_id = credit_ledger.account_id) AND (au.user_id = auth.uid())))));
CREATE POLICY "Users can view their own credit balance" ON kortix.credit_balance FOR SELECT TO authenticated USING ((account_id IN ( SELECT wu.account_id
   FROM basejump.account_user wu
  WHERE (wu.user_id = ( SELECT auth.uid() AS uid)))));
CREATE POLICY "Users can view their own credit usage" ON kortix.credit_usage FOR SELECT TO authenticated USING ((account_id IN ( SELECT wu.account_id
   FROM basejump.account_user wu
  WHERE (wu.user_id = ( SELECT auth.uid() AS uid)))));
CREATE POLICY "Users can view their own deletion requests" ON kortix.account_deletion_requests FOR SELECT USING ((auth.uid() = user_id));
CREATE POLICY team_members_can_view_credit_account ON kortix.credit_accounts FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM basejump.account_user au
  WHERE ((au.account_id = credit_accounts.account_id) AND (au.user_id = auth.uid())))));
CREATE POLICY team_members_can_view_ledger ON kortix.credit_ledger FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM basejump.account_user au
  WHERE ((au.account_id = credit_ledger.account_id) AND (au.user_id = auth.uid())))));
CREATE POLICY team_owners_can_manage_credits ON kortix.credit_accounts TO authenticated USING ((EXISTS ( SELECT 1
   FROM basejump.account_user au
  WHERE ((au.account_id = credit_accounts.account_id) AND (au.user_id = auth.uid()) AND (au.account_role = 'owner'::basejump.account_role)))));
CREATE POLICY "users can view credit accounts" ON kortix.credit_accounts FOR SELECT TO authenticated USING ((account_id IN ( SELECT wu.account_id
   FROM basejump.account_user wu
  WHERE (wu.user_id = ( SELECT auth.uid() AS uid)))));
CREATE POLICY "users can view credit ledger" ON kortix.credit_ledger FOR SELECT TO authenticated USING ((account_id IN ( SELECT wu.account_id
   FROM basejump.account_user wu
  WHERE (wu.user_id = ( SELECT auth.uid() AS uid)))));
CREATE POLICY "users can view credit purchases" ON kortix.credit_purchases FOR SELECT TO authenticated USING ((account_id IN ( SELECT wu.account_id
   FROM basejump.account_user wu
  WHERE (wu.user_id = ( SELECT auth.uid() AS uid)))));

-- ── public: billing idempotency tables (FK -> kortix.credit_accounts) ────────
CREATE TABLE public.daily_refresh_tracking (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    refresh_date date NOT NULL,
    credits_granted numeric(10,2) NOT NULL,
    tier text NOT NULL,
    processed_by text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);
CREATE TABLE public.renewal_processing (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    account_id uuid NOT NULL,
    period_start bigint NOT NULL,
    period_end bigint NOT NULL,
    subscription_id text NOT NULL,
    processed_by text NOT NULL,
    credits_granted numeric(10,2) NOT NULL,
    processed_at timestamp with time zone DEFAULT now(),
    stripe_event_id text,
    created_at timestamp with time zone DEFAULT now(),
    provider text DEFAULT 'stripe'::text,
    revenuecat_transaction_id text,
    revenuecat_product_id text,
    CONSTRAINT renewal_processing_processed_by_check CHECK ((processed_by = ANY (ARRAY['webhook_invoice'::text, 'webhook_subscription'::text, 'manual'::text, 'cron'::text, 'revenuecat_webhook'::text]))),
    CONSTRAINT renewal_processing_provider_check CHECK ((provider = ANY (ARRAY['stripe'::text, 'revenuecat'::text])))
);
ALTER TABLE ONLY public.daily_refresh_tracking
    ADD CONSTRAINT daily_refresh_tracking_account_id_refresh_date_key UNIQUE (account_id, refresh_date);
ALTER TABLE ONLY public.daily_refresh_tracking
    ADD CONSTRAINT daily_refresh_tracking_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.renewal_processing
    ADD CONSTRAINT renewal_processing_account_id_period_start_key UNIQUE (account_id, period_start);
ALTER TABLE ONLY public.renewal_processing
    ADD CONSTRAINT renewal_processing_pkey PRIMARY KEY (id);
CREATE INDEX idx_daily_refresh_tracking_account_date ON public.daily_refresh_tracking USING btree (account_id, refresh_date DESC);
CREATE INDEX idx_daily_refresh_tracking_created ON public.daily_refresh_tracking USING btree (created_at DESC);
CREATE INDEX idx_renewal_processing_account ON public.renewal_processing USING btree (account_id);
CREATE INDEX idx_renewal_processing_period ON public.renewal_processing USING btree (account_id, period_start);
CREATE INDEX idx_renewal_processing_provider ON public.renewal_processing USING btree (provider);
CREATE INDEX idx_renewal_processing_subscription ON public.renewal_processing USING btree (subscription_id);
ALTER TABLE ONLY public.daily_refresh_tracking
    ADD CONSTRAINT daily_refresh_tracking_account_id_fkey FOREIGN KEY (account_id) REFERENCES kortix.credit_accounts(account_id) ON DELETE CASCADE;
CREATE POLICY "Service role full access on renewal_processing" ON public.renewal_processing TO service_role USING ((( SELECT auth.role() AS role) = 'service_role'::text)) WITH CHECK ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Service role only access" ON public.daily_refresh_tracking TO service_role USING (true) WITH CHECK (true);
ALTER TABLE public.daily_refresh_tracking ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.renewal_processing ENABLE ROW LEVEL SECURITY;

-- ── public: atomic credit RPCs ───────────────────────────────────────────────
CREATE OR REPLACE FUNCTION public.atomic_add_credits(p_account_id uuid, p_amount numeric, p_is_expiring boolean DEFAULT true, p_description text DEFAULT 'Credit added'::text, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_type text DEFAULT NULL::text, p_stripe_event_id text DEFAULT NULL::text, p_idempotency_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
DECLARE
    v_current_expiring NUMERIC(10, 2);
    v_current_non_expiring NUMERIC(10, 2);
    v_current_balance NUMERIC(10, 2);
    v_new_expiring NUMERIC(10, 2);
    v_new_non_expiring NUMERIC(10, 2);
    v_new_total NUMERIC(10, 2);
    v_tier TEXT;
    v_ledger_id UUID;
BEGIN
    -- Idempotency: check stripe_event_id
    IF p_stripe_event_id IS NOT NULL THEN
        IF EXISTS (
            SELECT 1 FROM kortix.credit_ledger
            WHERE stripe_event_id = p_stripe_event_id
        ) THEN
            RETURN jsonb_build_object(
                'success', true,
                'message', 'Credit already added (duplicate prevented)',
                'duplicate_prevented', true
            );
        END IF;
    END IF;

    -- Idempotency: check idempotency_key
    IF p_idempotency_key IS NOT NULL THEN
        IF EXISTS (
            SELECT 1 FROM kortix.credit_ledger
            WHERE idempotency_key = p_idempotency_key
            AND created_at > NOW() - INTERVAL '1 hour'
        ) THEN
            RETURN jsonb_build_object(
                'success', true,
                'message', 'Credit already added (idempotent)',
                'duplicate_prevented', true
            );
        END IF;
    END IF;

    SELECT expiring_credits, non_expiring_credits, balance, tier
    INTO v_current_expiring, v_current_non_expiring, v_current_balance, v_tier
    FROM kortix.credit_accounts
    WHERE account_id = p_account_id
    FOR UPDATE;

    IF NOT FOUND THEN
        v_current_expiring := 0;
        v_current_non_expiring := 0;
        v_current_balance := 0;
        v_tier := 'none';

        INSERT INTO kortix.credit_accounts (
            account_id, expiring_credits, non_expiring_credits, balance, tier
        ) VALUES (
            p_account_id, 0, 0, 0, v_tier
        );
    END IF;

    IF p_is_expiring THEN
        v_new_expiring := v_current_expiring + p_amount;
        v_new_non_expiring := v_current_non_expiring;
    ELSE
        v_new_expiring := v_current_expiring;
        v_new_non_expiring := v_current_non_expiring + p_amount;
    END IF;

    v_new_total := v_new_expiring + v_new_non_expiring;

    UPDATE kortix.credit_accounts
    SET
        expiring_credits = v_new_expiring,
        non_expiring_credits = v_new_non_expiring,
        balance = v_new_total,
        updated_at = NOW()
    WHERE account_id = p_account_id;

    INSERT INTO kortix.credit_ledger (
        account_id, amount, balance_after, type, description,
        is_expiring, expires_at, stripe_event_id, idempotency_key, processing_source
    ) VALUES (
        p_account_id, p_amount, v_new_total,
        COALESCE(p_type, CASE WHEN p_is_expiring THEN 'tier_grant' ELSE 'purchase' END),
        p_description, p_is_expiring, p_expires_at,
        p_stripe_event_id, p_idempotency_key, 'atomic_function'
    ) RETURNING id INTO v_ledger_id;

    RETURN jsonb_build_object(
        'success', true,
        'expiring_credits', v_new_expiring,
        'non_expiring_credits', v_new_non_expiring,
        'total_balance', v_new_total,
        'ledger_id', v_ledger_id
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.atomic_daily_credit_refresh(p_account_id uuid, p_credit_amount numeric, p_tier text, p_processed_by text, p_refresh_interval_hours integer DEFAULT 24)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'kortix', 'public'
AS $function$
DECLARE
    v_last_refresh TIMESTAMPTZ;
    v_now TIMESTAMPTZ := NOW();
    v_refresh_date DATE := v_now::DATE;
    v_already_refreshed BOOLEAN;
    v_interval INTERVAL;
    v_should_refresh BOOLEAN := FALSE;
    v_old_daily NUMERIC(10, 2);
    v_old_total NUMERIC(10, 2);
    v_new_daily NUMERIC(10, 2);
    v_new_total NUMERIC(10, 2);
    v_tracking_id UUID;
    v_credits_added NUMERIC(10, 2);
BEGIN
    v_interval := (p_refresh_interval_hours || ' hours')::INTERVAL;

    SELECT last_daily_refresh, daily_credits_balance, balance
    INTO v_last_refresh, v_old_daily, v_old_total
    FROM kortix.credit_accounts
    WHERE account_id = p_account_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'reason', 'account_not_found',
            'duplicate_prevented', false
        );
    END IF;

    SELECT EXISTS(
        SELECT 1 FROM public.daily_refresh_tracking
        WHERE account_id = p_account_id AND refresh_date = v_refresh_date
    ) INTO v_already_refreshed;

    IF v_already_refreshed THEN
        RETURN jsonb_build_object(
            'success', false,
            'reason', 'already_refreshed_today',
            'duplicate_prevented', true,
            'refresh_date', v_refresh_date
        );
    END IF;

    IF v_last_refresh IS NULL THEN
        v_should_refresh := TRUE;
    ELSIF v_now - v_last_refresh > v_interval THEN
        v_should_refresh := TRUE;
    END IF;

    IF NOT v_should_refresh THEN
        RETURN jsonb_build_object(
            'success', false,
            'reason', 'interval_not_elapsed',
            'duplicate_prevented', false,
            'last_refresh', v_last_refresh,
            'next_refresh', v_last_refresh + v_interval
        );
    END IF;

    INSERT INTO public.daily_refresh_tracking (
        account_id, refresh_date, credits_granted, tier, processed_by
    ) VALUES (
        p_account_id, v_refresh_date, p_credit_amount, p_tier, p_processed_by
    )
    ON CONFLICT (account_id, refresh_date) DO NOTHING
    RETURNING id INTO v_tracking_id;

    IF v_tracking_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'reason', 'concurrent_refresh_prevented',
            'duplicate_prevented', true,
            'refresh_date', v_refresh_date
        );
    END IF;

    v_new_daily := p_credit_amount;
    v_credits_added := p_credit_amount - COALESCE(v_old_daily, 0);
    v_new_total := v_old_total + v_credits_added;

    UPDATE kortix.credit_accounts
    SET
        daily_credits_balance = v_new_daily,
        balance = v_new_total,
        last_daily_refresh = v_now,
        updated_at = v_now
    WHERE account_id = p_account_id;

    INSERT INTO kortix.credit_ledger (
        account_id, amount, balance_after, type, description,
        is_expiring, expires_at, metadata
    ) VALUES (
        p_account_id, v_credits_added, v_new_total, 'daily_refresh',
        format('Daily credits refresh: %s -> %s', COALESCE(v_old_daily, 0), v_new_daily),
        TRUE, v_now + v_interval,
        jsonb_build_object(
            'tier', p_tier,
            'refresh_date', v_refresh_date,
            'old_daily', v_old_daily,
            'new_daily', v_new_daily,
            'refresh_interval_hours', p_refresh_interval_hours,
            'tracking_id', v_tracking_id
        )
    );

    RETURN jsonb_build_object(
        'success', true,
        'credits_granted', v_credits_added,
        'new_daily_balance', v_new_daily,
        'new_total_balance', v_new_total,
        'refresh_date', v_refresh_date,
        'old_daily', v_old_daily,
        'duplicate_prevented', false,
        'tracking_id', v_tracking_id
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.atomic_grant_renewal_credits(p_account_id uuid, p_period_start bigint, p_period_end bigint, p_credits numeric, p_processed_by text, p_invoice_id text DEFAULT NULL::text, p_stripe_event_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
DECLARE
    v_already_processed BOOLEAN;
    v_existing_processor TEXT;
    v_current_non_expiring NUMERIC(10, 2);
    v_new_total NUMERIC(10, 2);
    v_expires_at TIMESTAMP WITH TIME ZONE;
BEGIN
    SELECT EXISTS(
        SELECT 1 FROM public.renewal_processing
        WHERE account_id = p_account_id AND period_start = p_period_start
    ), (
        SELECT processed_by FROM public.renewal_processing
        WHERE account_id = p_account_id AND period_start = p_period_start
        LIMIT 1
    ) INTO v_already_processed, v_existing_processor;

    IF v_already_processed THEN
        RETURN jsonb_build_object(
            'success', false,
            'reason', 'already_processed',
            'processed_by', v_existing_processor,
            'duplicate_prevented', true
        );
    END IF;

    INSERT INTO public.renewal_processing (
        account_id, period_start, period_end, subscription_id,
        processed_by, credits_granted, stripe_event_id
    )
    SELECT p_account_id, p_period_start, p_period_end, stripe_subscription_id,
           p_processed_by, p_credits, p_stripe_event_id
    FROM kortix.credit_accounts
    WHERE account_id = p_account_id;

    SELECT non_expiring_credits INTO v_current_non_expiring
    FROM kortix.credit_accounts WHERE account_id = p_account_id;

    v_current_non_expiring := COALESCE(v_current_non_expiring, 0);
    v_new_total := p_credits + v_current_non_expiring;
    v_expires_at := TO_TIMESTAMP(p_period_end);

    UPDATE kortix.credit_accounts
    SET
        expiring_credits = p_credits,
        balance = v_new_total,
        last_grant_date = TO_TIMESTAMP(p_period_start),
        next_credit_grant = TO_TIMESTAMP(p_period_end),
        last_processed_invoice_id = COALESCE(p_invoice_id, last_processed_invoice_id),
        last_renewal_period_start = p_period_start,
        updated_at = NOW()
    WHERE account_id = p_account_id;

    INSERT INTO kortix.credit_ledger (
        account_id, amount, balance_after, type, description,
        is_expiring, expires_at, stripe_event_id, processing_source
    ) VALUES (
        p_account_id, p_credits, v_new_total, 'tier_grant',
        'Monthly renewal: ' || p_processed_by,
        true, v_expires_at, p_stripe_event_id, p_processed_by
    );

    RETURN jsonb_build_object(
        'success', true,
        'credits_granted', p_credits,
        'new_balance', v_new_total,
        'expiring_credits', p_credits,
        'non_expiring_credits', v_current_non_expiring,
        'processed_by', p_processed_by
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'reason', 'error',
        'error', SQLERRM
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.atomic_grant_renewal_credits(p_account_id uuid, p_period_start bigint, p_period_end bigint, p_credits numeric, p_processed_by text, p_invoice_id text DEFAULT NULL::text, p_stripe_event_id text DEFAULT NULL::text, p_provider text DEFAULT 'stripe'::text, p_revenuecat_transaction_id text DEFAULT NULL::text, p_revenuecat_product_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
DECLARE
    v_already_processed BOOLEAN;
    v_existing_processor TEXT;
    v_current_daily NUMERIC(10, 2);
    v_current_non_expiring NUMERIC(10, 2);
    v_new_total NUMERIC(10, 2);
    v_expires_at TIMESTAMP WITH TIME ZONE;
    v_subscription_id TEXT;
BEGIN
    -- Check if this period was already processed (idempotency)
    SELECT EXISTS(
        SELECT 1 FROM public.renewal_processing 
        WHERE account_id = p_account_id 
        AND period_start = p_period_start
    ), (
        SELECT processed_by FROM public.renewal_processing
        WHERE account_id = p_account_id
        AND period_start = p_period_start
        LIMIT 1
    ) INTO v_already_processed, v_existing_processor;
    
    IF v_already_processed THEN
        RAISE NOTICE '[ATOMIC RENEWAL] Period % already processed by % for account %', 
            p_period_start, v_existing_processor, p_account_id;
        
        RETURN jsonb_build_object(
            'success', false, 
            'reason', 'already_processed',
            'processed_by', v_existing_processor,
            'duplicate_prevented', true
        );
    END IF;
    
    -- Get subscription_id based on provider
    IF p_provider = 'revenuecat' THEN
        SELECT COALESCE(revenuecat_subscription_id, 'unknown')
        INTO v_subscription_id
        FROM kortix.credit_accounts
        WHERE account_id = p_account_id;
    ELSE
        SELECT COALESCE(stripe_subscription_id, 'unknown')
        INTO v_subscription_id
        FROM kortix.credit_accounts
        WHERE account_id = p_account_id;
    END IF;
    
    -- Insert processing record (idempotency lock)
    INSERT INTO public.renewal_processing (
        account_id, 
        period_start, 
        period_end, 
        subscription_id,
        processed_by, 
        credits_granted, 
        stripe_event_id,
        provider,
        revenuecat_transaction_id,
        revenuecat_product_id
    ) VALUES (
        p_account_id,
        p_period_start,
        p_period_end,
        v_subscription_id,
        p_processed_by,
        p_credits,
        p_stripe_event_id,
        p_provider,
        p_revenuecat_transaction_id,
        p_revenuecat_product_id
    );
    
    RAISE NOTICE '[ATOMIC RENEWAL] Marked period % as processing by % for account % (provider: %)',
        p_period_start, p_processed_by, p_account_id, p_provider;
    
    -- Get current balances (including daily!)
    SELECT 
        COALESCE(daily_credits_balance, 0),
        COALESCE(non_expiring_credits, 0)
    INTO v_current_daily, v_current_non_expiring
    FROM kortix.credit_accounts
    WHERE account_id = p_account_id;
    
    -- Total = daily + monthly (new) + extra
    v_new_total := v_current_daily + p_credits + v_current_non_expiring;
    v_expires_at := TO_TIMESTAMP(p_period_end);
    
    -- Update: reset monthly credits, keep daily and extra intact
    UPDATE kortix.credit_accounts 
    SET 
        expiring_credits = p_credits,
        balance = v_new_total,
        last_grant_date = TO_TIMESTAMP(p_period_start),
        next_credit_grant = TO_TIMESTAMP(p_period_end),
        last_processed_invoice_id = COALESCE(p_invoice_id, last_processed_invoice_id),
        last_renewal_period_start = p_period_start,
        updated_at = NOW()
    WHERE account_id = p_account_id;
    
    -- Log to ledger
    INSERT INTO kortix.credit_ledger (
        account_id,
        amount,
        balance_after,
        type,
        description,
        is_expiring,
        expires_at,
        stripe_event_id,
        processing_source
    ) VALUES (
        p_account_id,
        p_credits,
        v_new_total,
        'tier_grant',
        'Monthly renewal: ' || p_processed_by,
        true,
        v_expires_at,
        p_stripe_event_id,
        p_processed_by
    );
    
    RAISE NOTICE '[ATOMIC RENEWAL] Granted % monthly credits to account %, new balance: % (daily: %, extra: %)',
        p_credits, p_account_id, v_new_total, v_current_daily, v_current_non_expiring;
    
    RETURN jsonb_build_object(
        'success', true,
        'credits_granted', p_credits,
        'new_balance', v_new_total,
        'daily_credits', v_current_daily,
        'expiring_credits', p_credits,
        'non_expiring_credits', v_current_non_expiring,
        'processed_by', p_processed_by,
        'provider', p_provider
    );
    
EXCEPTION WHEN OTHERS THEN
    RAISE WARNING '[ATOMIC RENEWAL] Error: % - %', SQLERRM, SQLSTATE;
    RETURN jsonb_build_object(
        'success', false,
        'reason', 'error',
        'error', SQLERRM
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.atomic_reset_expiring_credits(p_account_id uuid, p_new_credits numeric, p_description text DEFAULT 'Monthly credit renewal'::text, p_stripe_event_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
DECLARE
    v_current_balance NUMERIC(10, 2);
    v_current_expiring NUMERIC(10, 2);
    v_current_non_expiring NUMERIC(10, 2);
    v_actual_non_expiring NUMERIC(10, 2);
    v_new_total NUMERIC(10, 2);
    v_expires_at TIMESTAMP WITH TIME ZONE;
BEGIN
    SELECT balance, expiring_credits, non_expiring_credits
    INTO v_current_balance, v_current_expiring, v_current_non_expiring
    FROM kortix.credit_accounts
    WHERE account_id = p_account_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Account not found');
    END IF;

    IF v_current_balance <= v_current_non_expiring THEN
        v_actual_non_expiring := v_current_balance;
    ELSE
        v_actual_non_expiring := v_current_non_expiring;
    END IF;

    v_new_total := p_new_credits + v_actual_non_expiring;
    v_expires_at := DATE_TRUNC('month', NOW() + INTERVAL '1 month') + INTERVAL '1 month';

    UPDATE kortix.credit_accounts
    SET
        expiring_credits = p_new_credits,
        non_expiring_credits = v_actual_non_expiring,
        balance = v_new_total,
        updated_at = NOW()
    WHERE account_id = p_account_id;

    INSERT INTO kortix.credit_ledger (
        account_id, amount, balance_after, type, description,
        is_expiring, expires_at, stripe_event_id, metadata, processing_source
    ) VALUES (
        p_account_id, p_new_credits, v_new_total, 'tier_grant', p_description,
        true, v_expires_at, p_stripe_event_id,
        jsonb_build_object(
            'renewal', true,
            'non_expiring_preserved', v_actual_non_expiring,
            'previous_balance', v_current_balance
        ),
        'atomic_function'
    );

    RETURN jsonb_build_object(
        'success', true,
        'new_expiring', p_new_credits,
        'non_expiring', v_actual_non_expiring,
        'total_balance', v_new_total
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.atomic_use_credits(p_account_id uuid, p_amount numeric, p_description text, p_ledger_type text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''
AS $function$
        DECLARE
          v_daily NUMERIC(10,2); v_exp NUMERIC(10,2); v_nonexp NUMERIC(10,2); v_total NUMERIC(10,2);
          v_fd NUMERIC(10,2):=0; v_fe NUMERIC(10,2):=0; v_fn NUMERIC(10,2):=0;
          v_rem NUMERIC(10,2); v_nd NUMERIC(10,2); v_ne NUMERIC(10,2); v_nn NUMERIC(10,2); v_nt NUMERIC(10,2);
          v_tid UUID;
        BEGIN
          SELECT COALESCE(daily_credits_balance,0),COALESCE(expiring_credits,0),
                 COALESCE(non_expiring_credits,0),COALESCE(balance,0)
          INTO v_daily,v_exp,v_nonexp,v_total
          FROM kortix.credit_accounts WHERE account_id=p_account_id FOR UPDATE;
          IF NOT FOUND THEN RETURN jsonb_build_object('success',false,'error','No credit account found','required',p_amount,'available',0); END IF;
          v_rem:=p_amount;
          IF v_rem>0 AND v_daily>0 THEN IF v_daily>=v_rem THEN v_fd:=v_rem;v_rem:=0; ELSE v_fd:=v_daily;v_rem:=v_rem-v_daily; END IF; END IF;
          IF v_rem>0 AND v_exp>0 THEN IF v_exp>=v_rem THEN v_fe:=v_rem;v_rem:=0; ELSE v_fe:=v_exp;v_rem:=v_rem-v_exp; END IF; END IF;
          IF v_rem>0 THEN v_fn:=v_rem;v_rem:=0; END IF;
          v_nd:=v_daily-v_fd; v_ne:=v_exp-v_fe; v_nn:=v_nonexp-v_fn; v_nt:=v_nd+v_ne+v_nn;
          UPDATE kortix.credit_accounts SET daily_credits_balance=v_nd,expiring_credits=v_ne,
            non_expiring_credits=v_nn,balance=v_nt,updated_at=NOW() WHERE account_id=p_account_id;
          INSERT INTO kortix.credit_ledger(account_id,amount,balance_after,type,description,metadata)
          VALUES(p_account_id,-p_amount,v_nt,'usage',p_description,
            jsonb_build_object('from_daily',v_fd,'from_monthly',v_fe,'from_extra',v_fn,'ledger_type',p_ledger_type))
          RETURNING id INTO v_tid;
          RETURN jsonb_build_object('success',true,'amount_deducted',p_amount,'new_total',v_nt,
            'new_daily',v_nd,'new_expiring',v_ne,'new_non_expiring',v_nn,
            'from_daily',v_fd,'from_monthly',v_fe,'from_extra',v_fn,
            'from_expiring',v_fe,'from_non_expiring',v_fn,'transaction_id',v_tid);
        END;
    $function$
;

CREATE OR REPLACE FUNCTION public.atomic_use_credits(p_account_id uuid, p_amount numeric, p_description text DEFAULT 'Credit usage'::text, p_thread_id text DEFAULT NULL::text, p_message_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO ''
AS $function$
DECLARE
    v_daily_balance NUMERIC(10, 2);
    v_expiring_balance NUMERIC(10, 2);
    v_non_expiring_balance NUMERIC(10, 2);
    v_total_balance NUMERIC(10, 2);
    v_amount_from_daily NUMERIC(10, 2) := 0;
    v_amount_from_expiring NUMERIC(10, 2) := 0;
    v_amount_from_non_expiring NUMERIC(10, 2) := 0;
    v_remaining NUMERIC(10, 2);
    v_new_daily NUMERIC(10, 2);
    v_new_expiring NUMERIC(10, 2);
    v_new_non_expiring NUMERIC(10, 2);
    v_new_total NUMERIC(10, 2);
    v_transaction_id UUID;
BEGIN
    SELECT
        COALESCE(daily_credits_balance, 0),
        COALESCE(expiring_credits, 0),
        COALESCE(non_expiring_credits, 0),
        COALESCE(balance, 0)
    INTO
        v_daily_balance, v_expiring_balance, v_non_expiring_balance, v_total_balance
    FROM kortix.credit_accounts
    WHERE account_id = p_account_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'No credit account found',
            'required', p_amount,
            'available', 0
        );
    END IF;

    IF p_amount <= 0 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Amount must be positive',
            'required', p_amount,
            'available', v_total_balance
        );
    END IF;

    IF v_total_balance < p_amount THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Insufficient credits',
            'required', p_amount,
            'available', v_total_balance
        );
    END IF;

    v_remaining := p_amount;

    -- Step 1: Deduct from DAILY credits first
    IF v_remaining > 0 AND v_daily_balance > 0 THEN
        IF v_daily_balance >= v_remaining THEN
            v_amount_from_daily := v_remaining;
            v_remaining := 0;
        ELSE
            v_amount_from_daily := v_daily_balance;
            v_remaining := v_remaining - v_daily_balance;
        END IF;
    END IF;

    -- Step 2: Deduct from MONTHLY (expiring) credits second
    IF v_remaining > 0 AND v_expiring_balance > 0 THEN
        IF v_expiring_balance >= v_remaining THEN
            v_amount_from_expiring := v_remaining;
            v_remaining := 0;
        ELSE
            v_amount_from_expiring := v_expiring_balance;
            v_remaining := v_remaining - v_expiring_balance;
        END IF;
    END IF;

    -- Step 3: Deduct from EXTRA (non-expiring) credits last
    IF v_remaining > 0 AND v_non_expiring_balance > 0 THEN
        v_amount_from_non_expiring := v_remaining;
        v_remaining := 0;
    END IF;

    v_new_daily := v_daily_balance - v_amount_from_daily;
    v_new_expiring := v_expiring_balance - v_amount_from_expiring;
    v_new_non_expiring := v_non_expiring_balance - v_amount_from_non_expiring;
    v_new_total := v_new_daily + v_new_expiring + v_new_non_expiring;

    UPDATE kortix.credit_accounts
    SET
        daily_credits_balance = v_new_daily,
        expiring_credits = v_new_expiring,
        non_expiring_credits = v_new_non_expiring,
        balance = v_new_total,
        updated_at = NOW()
    WHERE account_id = p_account_id;

    INSERT INTO kortix.credit_ledger (
        account_id, amount, balance_after, type, description, metadata
    ) VALUES (
        p_account_id, -p_amount, v_new_total, 'usage', p_description,
        jsonb_build_object(
            'from_daily', v_amount_from_daily,
            'from_monthly', v_amount_from_expiring,
            'from_extra', v_amount_from_non_expiring,
            'thread_id', p_thread_id,
            'message_id', p_message_id
        )
    ) RETURNING id INTO v_transaction_id;

    RETURN jsonb_build_object(
        'success', true,
        'amount_deducted', p_amount,
        'new_total', v_new_total,
        'new_daily', v_new_daily,
        'new_expiring', v_new_expiring,
        'new_non_expiring', v_new_non_expiring,
        'from_daily', v_amount_from_daily,
        'from_monthly', v_amount_from_expiring,
        'from_extra', v_amount_from_non_expiring,
        'from_expiring', v_amount_from_expiring,
        'from_non_expiring', v_amount_from_non_expiring,
        'transaction_id', v_transaction_id
    );
END;
$function$
;


-- ── Grants ───────────────────────────────────────────────────────────────────
GRANT ALL ON ALL TABLES IN SCHEMA kortix TO service_role;
GRANT SELECT, INSERT, UPDATE ON ALL TABLES IN SCHEMA kortix TO authenticated;
GRANT SELECT ON ALL TABLES IN SCHEMA kortix TO anon;
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA kortix TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_add_credits(p_account_id uuid, p_amount numeric, p_is_expiring boolean, p_description text, p_expires_at timestamp with time zone, p_type text, p_stripe_event_id text, p_idempotency_key text) TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_daily_credit_refresh(p_account_id uuid, p_credit_amount numeric, p_tier text, p_processed_by text, p_refresh_interval_hours integer) TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_grant_renewal_credits(p_account_id uuid, p_period_start bigint, p_period_end bigint, p_credits numeric, p_processed_by text, p_invoice_id text, p_stripe_event_id text) TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_grant_renewal_credits(p_account_id uuid, p_period_start bigint, p_period_end bigint, p_credits numeric, p_processed_by text, p_invoice_id text, p_stripe_event_id text, p_provider text, p_revenuecat_transaction_id text, p_revenuecat_product_id text) TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_reset_expiring_credits(p_account_id uuid, p_new_credits numeric, p_description text, p_stripe_event_id text) TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_use_credits(p_account_id uuid, p_amount numeric, p_description text, p_ledger_type text) TO service_role, authenticated;
GRANT EXECUTE ON FUNCTION public.atomic_use_credits(p_account_id uuid, p_amount numeric, p_description text, p_thread_id text, p_message_id text) TO service_role, authenticated;
